rss.channel:
{{ config.title }}
  {%- if term %} - {{ term.Name }}
  {%- elif section.Title %} - {{ section.Title }}
  {%- endif -%}

{%- if section -%}
  {{ section.Permalink | safe }}
{%- else -%}
  {{ config.base_url | safe }}
{%- endif -%}

    {{ config.description }}
    Snow
    {{ current_lang | default:config.language }}

    {%- if pages | length > 0 %}
      {{ pages.First().Modified | default:pages.First().Date | date:"Mon, 02 Jan 2006 15:04:05 -0700" }}
    {%- endif %}
    {%- for page in pages|slice:":10" %}


        {{ page.Title }}
        {{ page.Date | date:"Mon, 02 Jan 2006 15:04:05 -0700" }}

          {%- if page.FrontMatter.Get("authors") -%}
            {{ page.FrontMatter.Get("authors")[0] }}
          {%- elif config.author -%}
            {{ config.author }}
          {%- else -%}
            Unknown
          {%- endif -%}

        {{ page.Permalink }}
        {{ page.Permalink }}
        {% if page.Summary %}{{ page.Summary }}{% else %}{{ page.Content }}{% endif %}

    {%- endfor %}
